terraform {
  required_version = ">= 1.13"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = ">= 4.60.0, < 5.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
  }
}

provider "azurerm" {
  features {}
  subscription_id = var.subscription_id
}

# Provider alias for SAP VNet operations (cross-subscription peering).
# Uses sap_subscription_id if provided, otherwise falls back to same subscription.
provider "azurerm" {
  alias           = "sap"
  features {}
  subscription_id = var.sap_subscription_id != "" ? var.sap_subscription_id : var.subscription_id
}

